    public class NetworkManager
    {
        private readonly HttpClient _http;
        private ClientWebSocket _ws;
        private string _baseUrl;
        private string _token;
        private string _playerId;

        public event Action<string> OnMessageReceived;

        public NetworkManager(string baseUrl)
        {
            _baseUrl = baseUrl.TrimEnd('/');
            _http = new HttpClient();
        }

        public async Task<AuthResponse> LoginAsync(string playerId, string playerName)
        {
            var req = new LoginRequest { playerId = playerId, playerName = playerName };
            var json = UnityEngine.JsonUtility.ToJson(req); // Assuming Unity
            var content = new StringContent(json, Encoding.UTF8, "application/json");

            var res = await _http.PostAsync($"{_baseUrl}/auth/login", content);
            res.EnsureSuccessStatusCode();

            var resJson = await res.Content.ReadAsStringAsync();
            var auth = UnityEngine.JsonUtility.FromJson<AuthResponse>(resJson);
            
            _token = auth.token;
            _playerId = auth.playerId;
            return auth;
        }

        public async Task JoinMatchmakerAsync(string gameType = "moba")
        {
            var req = new JoinMatchRequest { playerId = _playerId, gameType = gameType };
            var json = UnityEngine.JsonUtility.ToJson(req);
            var content = new StringContent(json, Encoding.UTF8, "application/json");

