        public async Task ConnectWebSocketAsync(string roomId, string gameType = "moba")
        {
            _ws = new ClientWebSocket();
            var wsUrl = _baseUrl.Replace("http", "ws") + 
                $"/ws?roomId={roomId}&playerId={_playerId}&token={_token}&gameType={gameType}";

            await _ws.ConnectAsync(new Uri(wsUrl), CancellationToken.None);
            _ = ReceiveLoopAsync();
        }

        private async Task ReceiveLoopAsync()
        {
            var buffer = new byte[8192];
            while (_ws.State == WebSocketState.Open)
            {
                var result = await _ws.ReceiveAsync(new ArraySegment<byte>(buffer), CancellationToken.None);
                if (result.MessageType == WebSocketMessageType.Close)
                {
                    await _ws.CloseAsync(WebSocketCloseStatus.NormalClosure, "Closed", CancellationToken.None);
                    break;
                }
                else if (result.MessageType == WebSocketMessageType.Text)
                {
                    var msg = Encoding.UTF8.GetString(buffer, 0, result.Count);
                    OnMessageReceived?.Invoke(msg);
                }
                // Binary payloads can be routed to OnBinaryMessageReceived
            }
        }

        public async Task SendBinaryAsync(byte[] data)
        {
            if (_ws?.State == WebSocketState.Open)
            {
                await _ws.SendAsync(new ArraySegment<byte>(data), WebSocketMessageType.Binary, true, CancellationToken.None);
            }
        }
